/***********************************************************************************************************
	Only allow via CLI
***********************************************************************************************************/
if (php_sapi_name() !== 'cli') { die("This script can only be executed from the command line."); exit(); }
	
// Resolve directory of the current script
$scriptDir = realpath(dirname(__FILE__));

// Move three levels up
$targetDir = realpath($scriptDir . '/../../..');

// Ensure target directory exists
$targetSubDir = $targetDir . '/_testing/sm_worker';
if (!is_dir($targetSubDir)) {
    mkdir($targetSubDir, 0777, true);
}

// Path to debug file
$debugFile = $targetSubDir . '/php_param.debug';

// Create or update debug file
if (!file_exists($debugFile)) {
    touch($debugFile);
}

// Set permissions recursively for _testing
$iterator = new RecursiveIteratorIterator(
    new RecursiveDirectoryIterator($targetDir . '/_testing', RecursiveDirectoryIterator::SKIP_DOTS),
    RecursiveIteratorIterator::SELF_FIRST
);

foreach ($iterator as $item) {
    chmod($item, 0777);
}
chmod($targetDir . '/_testing', 0777);

// Save the first argument into debug file
if (isset($argv[2])) {
    file_put_contents($debugFile, $argv[2]);
} else {
    // If no argument given, clear file
    file_put_contents($debugFile, "");
}